+    #[test]
+    #[ignore = "manual perf probe for file-backed connection-open schema reload"]
+    fn manual_perf_probe_connection_open_schema_reload_many_tables() {
+        const TABLES: usize = 32;
+        const DEFAULT_ITERATIONS: usize = 120;
+
+        let iterations = std::env::var("FSQLITE_SCHEMA_REOPEN_ITERS")
+            .ok()
+            .and_then(|value| value.parse::<usize>().ok())
+            .unwrap_or(DEFAULT_ITERATIONS);
+
+        let dir = tempfile::tempdir().unwrap();
+        let db_path = dir.path().join("schema_reopen_many_tables.db");
+        let db_str = db_path.to_string_lossy().to_string();
+
+        {
+            let conn = Connection::open(&db_str).unwrap();
+            conn.execute("PRAGMA foreign_keys = ON;").unwrap();
+            for table_index in 0..TABLES {
+                let table = format!("item_{table_index}");
+                conn.execute(&format!(
+                    "CREATE TABLE {table} (
+                        id INTEGER PRIMARY KEY AUTOINCREMENT,
+                        tenant_id TEXT NOT NULL,
+                        parent_id INTEGER REFERENCES {table}(id) ON DELETE SET NULL,
+                        name TEXT NOT NULL COLLATE NOCASE UNIQUE,
+                        sort_key INTEGER NOT NULL DEFAULT 0 CHECK(sort_key >= 0),
+                        body TEXT,
+                        created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,
+                        updated_at TEXT,
+                        UNIQUE(tenant_id, sort_key),
+                        CHECK(length(name) > 0)
+                    ) STRICT;"
+                ))
+                .unwrap();
+                conn.execute(&format!(
+                    "CREATE INDEX {table}_tenant_sort_idx ON {table}(tenant_id, sort_key);"
+                ))
+                .unwrap();
+            }
+        }
+
+        let mut samples_us = Vec::with_capacity(iterations);
+        let total_start = std::time::Instant::now();
+        for _ in 0..iterations {
+            let start = std::time::Instant::now();
+            let conn = Connection::open(&db_str).unwrap();
+            let rows = conn.query("SELECT COUNT(*) FROM item_0;").unwrap();
+            assert_eq!(rows[0].values()[0], SqliteValue::Integer(0));
+            samples_us.push(start.elapsed().as_micros());
+        }
+        let total = total_start.elapsed();
+        samples_us.sort_unstable();
+        let p50 = samples_us[samples_us.len() / 2];
+        let p95_index = (samples_us.len() * 95 / 100).min(samples_us.len() - 1);
+        let p95 = samples_us[p95_index];
+        println!(
+            "manual_perf_probe.connection_open_schema_reload tables={TABLES} iterations={iterations} total_ms={} p50_us={p50} p95_us={p95}",
+            total.as_millis()
+        );
+    }
